#include <iostream>
using namespace std;

int main() {
    // endl flushes the buffer:
    cout << "Using endl" << endl;

    // \n is faster (no flush):
    cout << "Using backslash-n" << '\n';

    // Chain multiple outputs:
    cout << "Name: " << "Alex" << ", Age: " << 25 << '\n';

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Single-line comment — C++ ignores this
    cout << "Comments are invisible." << endl;

    /*
     * Multi-line comment.
     * Use for longer explanations.
     */
    cout << "Code runs fine." << endl;

    return 0; // Successful exit
}

