#include <iostream>
using namespace std;

int main() {
    cout << 10 + 3 << endl;   // 13
    cout << 10 - 3 << endl;   // 7
    cout << 10 * 3 << endl;   // 30
    cout << 10 / 3 << endl;   // 3 (integer!)
    cout << 10.0 / 3 << endl; // 3.333...
    cout << 10 % 3 << endl;   // 1 (remainder)
    cout << (int)3.99 << endl; // 3 (truncate)

    return 0;
}
